mapper.select:
SELECT

FROM
    pairing


        species_id = #{speciesId}


        AND fiscal_year = #{fiscalYear}


        AND pairing_id = #{pairingId}


        AND male_parent_id = #{maleParentId}


        AND female_parent_id = #{femaleParentId}


ORDER BY
    species_id,
    fiscal_year DESC,
    pairing_id

SELECT

FROM
    pairing
WHERE
    species_id = #{speciesId}
    AND fiscal_year = #{fiscalYear}
    AND pairing_id = #{pairingId}

SELECT
    COUNT(*)
FROM
    pairing
WHERE
    species_id = #{speciesId}
    AND male_parent_id = #{maleParentId}
    AND female_parent_id = #{femaleParentId}
    AND pairing_date = #{pairingDate}

SELECT
    COUNT(*)
FROM
    pairing
WHERE
    species_id = #{speciesId}
    AND male_parent_id = #{maleParentId}
    AND female_parent_id = #{femaleParentId}
    AND pairing_date = #{pairingDate}
    AND NOT (
        species_id = #{excludeSpeciesId}
        AND fiscal_year = #{excludeFiscalYear}
        AND pairing_id = #{excludePairingId}
    )

mapper.update:
UPDATE pairing
SET
    species_id = #{pairing.speciesId},
    fiscal_year = #{pairing.fiscalYear},
    pairing_id = #{pairing.pairingId},
    male_parent_id = #{pairing.maleParentId},
    female_parent_id = #{pairing.femaleParentId},
    pairing_date = #{pairing.pairingDate},
    note = #{pairing.note}
WHERE
    species_id = #{speciesId}
    AND fiscal_year = #{fiscalYear}
    AND pairing_id = #{pairingId}

mapper.delete:
DELETE FROM pairing
WHERE
    species_id = #{speciesId}
    AND fiscal_year = #{fiscalYear}
    AND pairing_id = #{pairingId}
